class PlayerState(Enum):
    ALIVE = "alive"
    KNOCKED = "knocked"
    DEAD = "dead"
    SPECTATING = "spectating"


class GamePhase(Enum):
    WAITING = "waiting"
    DROPPING = "dropping"
