class GameMap:
    def __init__(self, width: float = 4000, depth: float = 4000):
        self.width = width
        self.depth = depth
        self.obstacles: List[Obstacle] = []
        self.loot_items: Dict[str, LootItem] = {}
        self._generate_map()
        self._spawn_loot()

    def _generate_map(self):
        random.seed(42)
        num_buildings = 150
        for _ in range(num_buildings):
            pos = Vector3(
                random.uniform(-self.width / 2 + 50, self.width / 2 - 50),
                0,
                random.uniform(-self.depth / 2 + 50, self.depth / 2 - 50),
            )
            w = random.uniform(10, 40)
            h = random.uniform(5, 25)
            d = random.uniform(10, 40)
            self.obstacles.append(Obstacle(pos, w, h, d))

        num_rocks = 200
        for _ in range(num_rocks):
            pos = Vector3(
                random.uniform(-self.width / 2, self.width / 2),
                0,
                random.uniform(-self.depth / 2, self.depth / 2),
            )
            size = random.uniform(2, 8)
            self.obstacles.append(Obstacle(pos, size, size, size))

    def _spawn_loot(self):
        weapon_types = [
            ("weapon", "Assault Rifle", {"damage": 25, "fire_rate": 8, "max_ammo": 30, "range": 500}),
            ("weapon", "Shotgun", {"damage": 80, "fire_rate": 1.5, "max_ammo": 8, "range": 50}),
            ("weapon", "Sniper Rifle", {"damage": 100, "fire_rate": 0.8, "max_ammo": 5, "range": 1000}),
            ("weapon", "SMG", {"damage": 18, "fire_rate": 12, "max_ammo": 35, "range": 200}),
            ("weapon", "Pistol", {"damage": 20, "fire_rate": 5, "max_ammo": 15, "range": 150}),
        ]
        consumable_types = [
            ("health", "Medkit", {"heal_amount": 100}),
            ("health", "Bandage", {"heal_amount": 25}),
            ("armor", "Armor Plate", {"armor_amount": 50}),
            ("ammo", "Ammo Box", {"ammo_amount": 60}),
        ]

        for _ in range(400):
            pos = Vector3(
                random.uniform(-self.width / 2, self.width / 2),
                0,
                random.uniform(-self.depth / 2, self.depth / 2),
            )
            if random.random() < 0.4:
                item_type, item_name, props = random.choice(weapon_types)
            else:
                item_type, item_name, props = random.choice(consumable_types)

            item_id = str(uuid.uuid4())[:8]
            self.loot_items[item_id] = LootItem(
                item_id=item_id,
                item_type=item_type,
                item_name=item_name,
                position=pos,
                properties=props,
            )

    def raycast(self, start: Vector3, end: Vector3) -> bool:
        """Simple ray-obstacle intersection. Returns True if line of sight is clear."""
        steps = 50
        dx = (end.x - start.x) / steps
        dz = (end.z - start.z) / steps

        for i in range(steps + 1):
            px = start.x + dx * i
            pz = start.z + dz * i
            for obs in self.obstacles:
                if obs.contains_point_xz(px, pz):
                    return False
        return True

    def to_dict(self) -> dict:
        return {
            "width": self.width,
            "depth": self.depth,
            "obstacles": [o.to_dict() for o in self.obstacles],
            "loot_items": {k: v.to_dict() for k, v in self.loot_items.items() if not v.picked_up},
        }


class BattleRoyaleServer:
    def __init__(self, host: str = "0.0.0.0", port: int = 8765):
        self.host = host
        self.port = port
        self.players: Dict[str, Player] = {}
        self.connections: Dict[str, websockets.WebSocketServerProtocol] = {}
        self.game_phase: GamePhase = GamePhase.WAITING
        self.game_map = GameMap()
        self.projectiles: Dict[str, Projectile] = {}
        self.events: List[GameEvent] = []
        self.zone = Zone(
            center=Vector3(0, 0, 0),
            current_radius=2000,
            target_radius=2000,
            shrink_rate=0,
            damage_per_second=1,
            phase=0,
        )
        self.tick_rate = 20  # ticks per second
        self.broadcast_rate = 20  # full state broadcasts per second
        self.max_players = 100
        self.min_players_to_start = 2
        self.game_start_countdown = 10.0
        self.countdown_timer: Optional[float] = None
        self.alive_count = 0
        self.match_id = str(uuid.uuid4())[:8]
        self.server_start_time = time.time()
        self.last_zone_update = time.time()
        self.zone_timings = [
            {"delay": 120, "shrink_duration": 60, "target_radius": 1500, "damage": 1},
            {"delay": 90, "shrink_duration": 50, "target_radius": 1000, "damage": 2},
            {"delay": 75, "shrink_duration": 45, "target_radius": 600, "damage": 5},
            {"delay": 60, "shrink_duration": 40, "target_radius": 300, "damage": 8},
            {"delay": 45, "shrink_duration": 30, "target_radius": 100, "damage": 10},
            {"delay": 30, "shrink_duration": 20, "target_radius": 25, "damage": 15},
            {"delay": 15, "shrink_duration": 10, "target_radius": 0, "damage": 25},
        ]
        self.zone_phase_start_time: Optional[float] = None
        self.zone_shrinking = False
        self.kill_feed: List[dict] = []
        self.running = False

    async def start(self):
        self.running = True
        logger.info(f"Starting Battle Royale Server on {self.host}:{self.port}")
        logger.info(f"Match ID: {self.match_id}")

        server = await websockets.serve(
            self.handle_connection,
            self.host,
            self.port,
            ping_interval=10,
            ping_timeout=30,
            max_size=2**20,
        )

        logger.info("Server started. Waiting for connections...")

        game_loop_task = asyncio.create_task(self.game_loop())
        broadcast_task = asyncio.create_task(self.broadcast_loop())

        try:
            await asyncio.gather(game_loop_task, broadcast_task)
        except asyncio.CancelledError:
            pass
        finally:
            server.close()
            await server.wait_closed()

    async def handle_connection(self, websocket: websockets.WebSocketServerProtocol, path: str = ""):
        player_id = str(uuid.uuid4())[:12]
        logger.info(f"New connection from {websocket.remote_address}, assigned ID: {player_id}")

        try:
            # Wait for join message
            raw = await asyncio.wait_for(websocket.recv(), timeout=10)
            message = json.loads(raw)

            if message.get("type") != "join":
                await websocket.send(json.dumps({"type": "error", "message": "Expected join message"}))
                return

            username = message.get("username", f"Player_{player_id[:4]}")

            if len(self.players) >= self.max_players:
                await websocket.send(json.dumps({"type": "error", "message": "Server is full"}))
                return

            if self.game_phase not in (GamePhase.WAITING, GamePhase.DROPPING):
                await websocket.send(json.dumps({
                    "type": "error",
                    "message": "Game already in progress"
                }))
                return

            # Create player
            spawn_pos = Vector3(
                random.uniform(-500, 500),
                500,  # start high for dropping
                random.uniform(-500, 500),
            )

            player = Player(
                player_id=player_id,
                username=username,
                position=spawn_pos,
                last_update_time=time.time(),
                team_id=message.get("team_id"),
            )

            self.players[player_id] = player
            self.connections[player_id] = websocket
            self.alive_count = sum(1 for p in self.players.values()
                                   if p.state == PlayerState.ALIVE and p.connected)

            # Send welcome packet with full game state
            welcome = {
                "type": "welcome",
                "player_id": player_id,
                "match_id": self.match_id,
                "game_phase": self.game_phase.value,
                "map_data": self.game_map.to_dict(),
                "zone": self.zone.to_dict(),
                "server_tick_rate": self.tick_rate,
                "player_count": len(self.players),
                "max_players": self.max_players,
            }
            await websocket.send(json.dumps(welcome))

            # Notify all players
            await self.broadcast_event("player_joined", {
                "player_id": player_id,
                "username": username,
                "player_count": len(self.players),
            })

            logger.info(f"Player '{username}' ({player_id}) joined. "
                        f"Players: {len(self.players)}/{self.max_players}")

            # Handle messages from this player
            async for raw_message in websocket:
                try:
                    msg = json.loads(raw_message)
                    await self.handle_message(player_id, msg)
                except json.JSONDecodeError:
                    logger.warning(f"Invalid JSON from {player_id}")
                except Exception as e:
                    logger.error(f"Error handling message from {player_id}: {e}")

        except websockets.ConnectionClosed:
            logger.info(f"Connection closed for {player_id}")
        except asyncio.TimeoutError:
            logger.info(f"Connection timeout for {player_id}")
        except Exception as e:
            logger.error(f"Error in connection handler for {player_id}: {e}")
        finally:
            await self.handle_disconnect(player_id)

    async def handle_message(self, player_id: str, message: dict):
        msg_type = message.get("type")
        player = self.players.get(player_id)

        if not player or not player.connected:
            return

        if msg_type == "position_update":
            await self.handle_position_update(player, message)
        elif msg_type == "shoot":
            await self.handle_shoot(player, message)
        elif msg_type == "reload":
            await self.handle_reload(player, message)
        elif msg_type == "switch_weapon":
            await self.handle_switch_weapon(player, message)
        elif msg_type == "pickup_item":
            await self.handle_pickup_item(player, message)
        elif msg_type == "drop_item":
            await self.handle_drop_item(player, message)
        elif msg_type == "use_item":
            await self.handle_use_item(player, message)
        elif msg_type == "ping":
            await self.handle_ping(player_id, message)
        elif msg_type == "emote":
            await self.broadcast_event("emote", {
                "player_id": player_id,
                "emote_id": message.get("emote_id", "wave"),
            })

    async def handle_position_update(self, player: Player, message: dict):
        if player.state != PlayerState.ALIVE:
            return

        now = time.time()
        new_pos = Vector3.from_dict(message.get("position", {}))
        new_vel = Vector3.from_dict(message.get("velocity", {}))

        # Basic anti-cheat: speed check
        if player.last_update_time > 0:
            dt = now - player.last_update_time
            if dt > 0:
                dist = player.position.distance_to(new_pos)
                speed = dist / dt
                max_speed = 30.0  # units per second
                if speed > max_speed * 1.5:
                    logger.warning(f"Speed hack detected for {player.username}: {speed:.1f} u/s")
                    # Reject the update
                    await self.send_to_player(player.player_id, {
                        "type": "position_correction",
                        "position": player.position.to_dict(),
                    })
                    return

        # Clamp to map bounds
        half_w = self.game_map.width / 2
        half_d = self.game_map.depth / 2
        new_pos.x = max(-half_w, min(half_w, new_pos.x))
        new_pos.z = max(-half_d, min(half_d, new_pos.z))
        new_pos.y = max(0, new_pos.y)

        player.position = new_pos
        player.velocity = new_vel
        player.rotation = message.get("rotation", player.rotation)
        player.pitch = message.get("pitch", player.pitch)
        player.last_update_time = now

    async def handle_shoot(self, player: Player, message: dict):
        if player.state != PlayerState.ALIVE:
            return
        if self.game_phase not in (GamePhase.PLAYING, GamePhase.FINAL_CIRCLE):
            return

        now = time.time()
        weapon = player.weapons[player.active_weapon_slot]

        if weapon is None:
            # Fist/melee attack
            await self.handle_melee(player, message)
            return

        # Check fire rate
        min_interval = 1.0 / weapon.fire_rate
        if now - player.last_shot_time < min_interval * 0.9:
            return

        if weapon.ammo <= 0:
            await self.send_to_player(player.player_id, {
                "type": "out_of_ammo",
                "weapon_slot": player.active_weapon_slot,
            })
            return

        weapon.ammo -= 1
        player.last_shot_time = now

        # Create projectile / hitscan
        direction = message.get("direction", {"x": 0, "y": 0, "z": 1})
        dir_vec = Vector3.from_dict(direction)

        # Apply spread
        spread_rad = math.radians(weapon.spread)
        dir_vec.x += random.uniform(-spread_rad, spread_rad)
        dir_vec.y += random.uniform(-spread_rad, spread_rad)
        dir_vec.z += random.uniform(-spread_rad, spread_rad)

        # Normalize
        mag = math.sqrt(dir_vec.x**2 + dir_vec.y**2 + dir_vec.z**2)
        if mag > 0:
            dir_vec.x /= mag
            dir_vec.y /= mag
            dir_vec.z /= mag

        # Hitscan - check for hits
        hit_player, hit_distance = self.hitscan(player, dir_vec, weapon.range)

        shot_event = {
            "player_id": player.player_id,
            "position": player.position.to_dict(),
            "direction": dir_vec.to_dict(),
            "weapon": weapon.weapon_name,
            "hit_player_id": None,
            "hit_position": None,
        }

        if hit_player and hit_player.state == PlayerState.ALIVE:
            # Calculate damage with distance falloff
            damage = weapon.damage
            if hit_distance > weapon.range * 0.5:
                falloff = 1.0 - ((hit_distance - weapon.range * 0.5) / (weapon.range * 0.5))
                damage *= max(0.3, falloff)

            # Headshot detection (simplified)
            is_headshot = message.get("aim_height", 0.5) > 0.8
            if is_headshot:
                damage *= 2.0

            await self.apply_damage(hit_player, damage, player, is_headshot)

            shot_event["hit_player_id"] = hit_player.player_id
            hit_pos = Vector3(
                player.position.x + dir_vec.x * hit_distance,
                player.position.y + dir_vec.y * hit_distance,
                player.position.z + dir_vec.z * hit_distance,
            )
            shot_event["hit_position"] = hit_pos.to_dict()
            shot_event["headshot"] = is_headshot

        await self.broadcast_event("shot_fired", shot_event)

    async def handle_melee(self, player: Player, message: dict):
        melee_range = 3.0
        melee_damage = 30.0

        for other in self.players.values():
            if other.player_id == player.player_id:
                continue
            if other.state != PlayerState.ALIVE:
                continue
            if player.position.distance_to(other.position) <= melee_range:
                await self.apply_damage(other, melee_damage, player, False)
                await self.broadcast_event("melee_hit", {
                    "attacker_id": player.player_id,
                    "victim_id": other.player_id,
                    "damage": melee_damage,
                })
                break

    def hitscan(self, shooter: Player, direction: Vector3, max_range: float) -> Tuple[Optional[Player], float]:
        """Cast a ray and find the first player hit."""
        best_hit = None
        best_dist = max_range

        for other in self.players.values():
            if other.player_id == shooter.player_id:
                continue
            if other.state != PlayerState.ALIVE:
                continue

            # Ray-sphere intersection (simplified hitbox as sphere)
            hitbox_radius = 1.5

            # Vector from ray origin to sphere center
            oc_x = shooter.position.x - other.position.x
            oc_y = (shooter.position.y + 1.5) - (other.position.y + 1.0)  # eye height -> body center
            oc_z = shooter.position.z - other.position.z

            a = direction.x**2 + direction.y**2 + direction.z**2
            b = 2.0 * (oc_x * direction.x + oc_y * direction.y + oc_z * direction.z)
            c = oc_x**2 + oc_y**2 + oc_z**2 - hitbox_radius**2

            discriminant = b * b - 4 * a * c

            if discriminant >= 0:
                t = (-b - math.sqrt(discriminant)) / (2 * a)
                if 0 < t < best_dist:
                    # Check line of sight to this point
                    hit_point = Vector3(
                        shooter.position.x + direction.x * t,
                        shooter.position.y + direction.y * t,
                        shooter.position.z + direction.z * t,
                    )
                    if self.game_map.raycast(shooter.position, hit_point):
                        best_hit = other
                        best_dist = t

        return best_hit, best_dist

    async def apply_damage(self, victim: Player, damage: float, attacker: Player, headshot: bool):
        if victim.state != PlayerState.ALIVE:
            return

        # Armor absorbs some damage
        armor_absorption = min(victim.armor, damage * 0.5)
        victim.armor -= armor_absorption
        remaining_damage = damage - armor_absorption
        victim.health -= remaining_damage

        attacker.damage_dealt += damage
        victim.last_hit_time = time.time()

        await self.broadcast_event("damage", {
            "victim_id": victim.player_id,
            "attacker_id": attacker.player_id,
            "damage": damage,
            "remaining_health": max(0, victim.health),
            "remaining_armor": max(0, victim.armor),
            "headshot": headshot,
        })

        # Send hit marker to attacker
        await self.send_to_player(attacker.player_id, {
            "type": "hit_marker",
            "victim_id": victim.player_id,
            "damage": damage,
            "headshot": headshot,
        })

        if victim.health <= 0:
            await self.handle_kill(victim, attacker)

    async def handle_kill(self, victim: Player, killer: Player):
        victim.state = PlayerState.DEAD
        victim.health = 0
        killer.kills += 1

        kill_info = {
            "killer_id": killer.player_id,
            "killer_name": killer.username,
            "victim_id": victim.player_id,
            "victim_name": victim.username,
            "weapon": (killer.weapons[killer.active_weapon_slot].weapon_name
                       if killer.weapons[killer.active_weapon_slot] else "Fists"),
            "timestamp": time.time(),
        }

        self.kill_feed.append(kill_info)
        if len(self.kill_feed) > 20:
            self.kill_feed = self.kill_feed[-20:]

        await self.broadcast_event("kill", kill_info)

        # Drop victim's loot
        await self.drop_death_loot(victim)

        # Update alive count
        self.alive_count = sum(1 for p in self.players.values()
                               if p.state == PlayerState.ALIVE and p.connected)

        logger.info(f"{killer.username} eliminated {victim.username}. "
                    f"Alive: {self.alive_count}")

        # Check for victory
        if self.alive_count <= 1 and self.game_phase in (GamePhase.PLAYING, GamePhase.FINAL_CIRCLE):
            await self.handle_game_end()

    async def drop_death_loot(self, player: Player):
        for weapon in player.weapons:
            if weapon:
                item_id = str(uuid.uuid4())[:8]
                loot = LootItem(
                    item_id=item_id,
                    item_type="weapon",
                    item_name=weapon.weapon_name,
                    position=Vector3(
                        player.position.x + random.uniform(-2, 2),
                        0,
                        player.position.z + random.uniform(-2, 2),
                    ),
                    properties={
                        "damage": weapon.damage,
                        "fire_rate": weapon.fire_rate,
                        "max_ammo": weapon.max_ammo,
                        "range": weapon.range,
                        "ammo": weapon.ammo,
                        "spread": weapon.spread,
                    }
                )
                self.game_map.loot_items[item_id] = loot

    async def handle_reload(self, player: Player, message: dict):
        weapon = player.weapons[player.active_weapon_slot]
        if weapon is None:
            return
        if weapon.ammo >= weapon.max_ammo:
            return

        # Instant reload for simplicity (client handles animation timing)
        weapon.ammo = weapon.max_ammo

        await self.send_to_player(player.player_id, {
            "type": "reload_complete",
            "weapon_slot": player.active_weapon_slot,
            "ammo": weapon.ammo,
        })

    async def handle_switch_weapon(self, player: Player, message: dict):
        slot = message.get("slot", 0)
        if 0 <= slot < len(player.weapons):
            player.active_weapon_slot = slot
            await self.send_to_player(player.player_id, {
                "type": "weapon_switched",
                "slot": slot,
                "weapon": player.weapons[slot].to_dict() if player.weapons[slot] else None,
            })

    async def handle_pickup_item(self, player: Player, message: dict):
        if player.state != PlayerState.ALIVE:
            return

        item_id = message.get("item_id")
        item = self.game_map.loot_items.get(item_id)

        if not item or item.picked_up:
            return

        # Check distance
        if player.position.distance_to(item.position) > 5.0:
            return

        item.picked_up = True

        if item.item_type == "weapon":
            # Equip weapon
            weapon = Weapon(
                weapon_name=item.item_name,
                damage=item.properties.get("damage", 20),
                fire_rate=item.properties.get("fire_rate", 5),
                ammo=item.properties.get("ammo", item.properties.get("max_ammo", 30)),
                max_ammo=item.properties.get("max_ammo", 30),
                reload_time=item.properties.get("reload_time", 2.0),
                range=item.properties.get("range", 200),
                spread=item.properties.get("spread", 1.0),
            )

            # Find empty slot or replace current
            placed = False
            for i in range(len(player.weapons)):
                if player.weapons[i] is None:
                    player.weapons[i] = weapon
                    player.active_weapon_slot = i
                    placed = True
                    break

            if not placed:
                # Drop current weapon, pick up new one
                old_weapon = player.weapons[player.active_weapon_slot]
                if old_weapon:
                    drop_id = str(uuid.uuid4())[:8]
                    drop_item = LootItem(
                        item_id=drop_id,
                        item_type="weapon",
                        item_name=old_weapon.weapon_name,
                        position=Vector3(player.position.x, 0, player.position.z),
                        properties={
                            "damage": old_weapon.damage,
                            "fire_rate": old_weapon.fire_rate,
                            "max_ammo": old_weapon.max_ammo,
                            "range": old_weapon.range,
                            "ammo": old_weapon.ammo,
                            "spread": old_weapon.spread,
                        }
                    )
                    self.game_map.loot_items[drop_id] = drop_item
                player.weapons[player.active_weapon_slot] = weapon

        elif item.item_type == "health":
            heal_amount = item.properties.get("heal_amount", 25)
            player.health = min(100, player.health + heal_amount)
        elif item.item_type == "armor":
            armor_amount = item.properties.get("armor_amount", 50)
            player.armor = min(100, player.armor + armor_amount)
        elif item.item_type == "ammo":
            weapon = player.weapons[player.active_weapon_slot]
            if weapon:
                weapon.ammo = min(weapon.max_ammo, weapon.ammo + item.properties.get("ammo_amount", 30))

        await self.send_to_player(player.player_id, {
            "type": "item_picked_up",
            "item_id": item_id,
            "item_type": item.item_type,
            "item_name": item.item_name,
            "player_data": player.to_dict(),
        })

        await self.broadcast_event("item_removed", {"item_id": item_id})

    async def handle_drop_item(self, player: Player, message: dict):
        slot = message.get("slot", player.active_weapon_slot)
        if 0 <= slot < len(player.weapons) and player.weapons[slot]:
            weapon = player.weapons[slot]
            item_id = str(uuid.uuid4())[:8]
            loot = LootItem(
                item_id=item_id,
                item_type="weapon",
                item_name=weapon.weapon_name,
                position=Vector3(player.position.x, 0, player.position.z),
                properties={
                    "damage": weapon.damage,
                    "fire_rate": weapon.fire_rate,
                    "max_ammo": weapon.max_ammo,
                    "range": weapon.range,
                    "ammo": weapon.ammo,
                    "spread": weapon.spread,
                }
            )
            self.game_map.loot_items[item_id] = loot
            player.weapons[slot] = None

            await self.send_to_player(player.player_id, {
                "type": "item_dropped",
                "slot": slot,
            })

            await self.broadcast_event("item_spawned", loot.to_dict())

    async def handle_use_item(self, player: Player, message: dict):
        item_type = message.get("item_type")
        if item_type == "health":
            for i, inv_item in enumerate(player.inventory):
                if inv_item.get("item_type") == "health":
                    heal = inv_item.get("properties", {}).get("heal_amount", 25)
                    player.health = min(100, player.health + heal)
                    player.inventory.pop(i)
                    await self.send_to_player(player.player_id, {
                        "type": "item_used",
                        "health": player.health,
                    })
                    break

    async def handle_ping(self, player_id: str, message: dict):
        client_time = message.get("client_time", 0)
        await self.send_to_player(player_id, {
            "type": "pong",
            "client_time": client_time,
            "server_time": time.time(),
        })

    async def handle_disconnect(self, player_id: str):
        if player_id in self.connections:
            del self.connections[player_id]

        if player_id in self.players:
            player = self.players[player_id]
            player.connected = False
            player.state = PlayerState.DEAD

            self.alive_count = sum(1 for p in self.players.values()
                                   if p.state == PlayerState.ALIVE and p.connected)

            logger.info(f"Player '{player.username}' disconnected. Alive: {self.alive_count}")

            await self.broadcast_event("player_left", {
                "player_id": player_id,
                "username": player.username,
                "player_count": self.alive_count,
            })

            if (self.alive_count <= 1 and
                    self.game_phase in (GamePhase.PLAYING, GamePhase.FINAL_CIRCLE)):
                await self.handle_game_end()

    async def game_loop(self):
        """Main server game loop."""
        last_tick = time.time()

        while self.running:
            now = time.time()
            dt = now - last_tick
            last_tick = now

            try:
                if self.game_phase == GamePhase.WAITING:
                    await self.update_waiting(dt)
                elif self.game_phase == GamePhase.DROPPING:
                    await self.update_dropping(dt)
                elif self.game_phase in (GamePhase.PLAYING, GamePhase.FINAL_CIRCLE):
                    await self.update_playing(dt)
                elif self.game_phase == GamePhase.ENDED:
                    pass

            except Exception as e:
                logger.error(f"Error in game loop: {e}")

            # Sleep to maintain tick rate
            elapsed = time.time() - now
            sleep_time = max(0, (1.0 / self.tick_rate) - elapsed)
            await asyncio.sleep(sleep_time)

    async def update_waiting(self, dt: float):
        connected_count = sum(1 for p in self.players.values() if p.connected)

        if connected_count >= self.min_players_to_start:
            if self.countdown_timer is None:
                self.countdown_timer = self.game_start_countdown
                await self.broadcast_event("countdown_started", {
                    "countdown": self.countdown_timer,
                })

            self.countdown_timer -= dt

            if self.countdown_timer <= 0:
                await self.start_game()
        else:
            if self.countdown_timer is not None:
                self.countdown_timer = None
                await self.broadcast_event("countdown_cancelled", {
                    "reason": "Not enough players",
                })

    async def start_game(self):
        logger.info("Game starting!")
        self.game_phase = GamePhase.DROPPING

        # Reset all players
        for player in self.players.values():
            if player.connected:
                player.state = PlayerState.ALIVE
                player.health = 100
                player.armor = 0
                # Random drop position along a flight path
                t = random.random()
                player.position = Vector3(
                    -1500 + 3000 * t + random.uniform(-50, 50),
                    500,
                    -1500 + 3000 * t + random.uniform(-50, 50),
                )

        self.alive_count = sum(1 for p in self.players.values()
                               if p.state == PlayerState.ALIVE and p.connected)

        await self.broadcast_event("game_starting", {
            "phase": GamePhase.DROPPING.value,
            "alive_count": self.alive_count,
            "flight_path": {
                "start": {"x": -1500, "y": 500, "z": -1500},
                "end": {"x": 1500, "y": 500, "z": 1500},
            },
        })

        # Auto-transition to playing after drop phase
        asyncio.create_task(self._drop_phase_timer())

    async def _drop_phase_timer(self):
        await asyncio.sleep(30)  # 30 second drop phase
        if self.game_phase == GamePhase.DROPPING:
            self.game_phase = GamePhase.PLAYING
            self.zone_phase_start_time = time.time()
            self.zone.phase = 0

            # Ground all players still in air
            for player in self.players.values():
                if player.position.y > 0:
                    player.position.y = 0

            await self.broadcast_event("game_phase_changed", {
                "phase": GamePhase.PLAYING.value,
                "zone": self.zone.to_dict(),
            })
            logger.info("Playing phase started")

    async def update_dropping(self, dt: float):
        # Players are dropping - let gravity work on client side
        for player in self.players.values():
            if player.position.y > 0 and player.state == PlayerState.ALIVE:
                player.position.y = max(0, player.position.y - 50 * dt)

    async def update_playing(self, dt: float):
        now = time.time()

        # Update zone
        await self.update_zone(dt, now)

        # Apply zone damage
        for player in self.players.values():
            if player.state != PlayerState.ALIVE or not player.connected:
                continue
            if not self.zone.is_inside(player.position):
                player.health -= self.zone.damage_per_second * dt
                if player.health <= 0:
                    player.health = 0
                    player.state = PlayerState.DEAD
                    self.alive_count -= 1

                    await self.broadcast_event("zone_kill", {
                        "player_id": player.player_id,
                        "username": player.username,
                    })

                    kill_info = {
                        "killer_id": "zone",
                        "killer_name": "The Zone",
                        "victim_id": player.player_id,
                        "victim_name": player.username,
                        "weapon": "Zone",
                        "timestamp": now,
                    }
                    self.kill_feed.append(kill_info)
                    await self.broadcast_event("kill", kill_info)

                    if self.alive_count <= 1:
                        await self.handle_game_end()

    async def update_zone(self, dt: float, now: float):
        if self.zone.phase >= len(self.zone_timings):
            return

        timing = self.zone_timings[self.zone.phase]
        elapsed = now - (self.zone_phase_start_time or now)

        if not self.zone_shrinking:
            if elapsed >= timing["delay"]:
                # Start shrinking
                self.zone_shrinking = True
                self.zone.target_radius = timing["target_radius"]
                self.zone.damage_per_second = timing["damage"]

                # New zone center (shift towards a random point)
                max_offset = self.zone.current_radius * 0.3
                self.zone.center = Vector3(
                    self.zone.center.x + random.uniform(-max_offset, max_offset),
                    0,
                    self.zone.center.z + random.uniform(-max_offset, max_offset),
                )

                self.zone.shrink_rate = (
                    (self.zone.current_radius - self.zone.target_radius) /
                    timing["shrink_duration"]
                )

                await self.broadcast_event("zone_shrinking", {
                    "zone": self.zone.to_dict(),
                    "shrink_duration": timing["shrink_duration"],
                })

                logger.info(f"Zone phase {self.zone.phase} shrinking: "
                            f"{self.zone.current_radius:.0f} -> {self.zone.target_radius:.0f}")
        else:
            # Shrink the zone
            self.zone.current_radius -= self.zone.shrink_rate * dt
            if self.zone.current_radius <= self.zone.target_radius:
                self.zone.current_radius = self.zone.target_radius
                self.zone_shrinking = False
                self.zone.phase += 1
                self.zone_phase_start_time = now

                if self.zone.phase >= len(self.zone_timings):
                    self.game_phase = GamePhase.FINAL_CIRCLE

                await self.broadcast_event("zone_phase_complete", {
                    "zone": self.zone.to_dict(),
                    "next_phase": self.zone.phase,
                })

                logger.info(f"Zone phase {self.zone.phase - 1} complete. "
                            f"Radius: {self.zone.current_radius:.0f}")

    async def handle_game_end(self):
        self.game_phase = GamePhase.ENDED

        winner = None
        for player in self.players.values():
            if player.state == PlayerState.ALIVE and player.connected:
                winner = player
                break

        # Build final standings
        standings = sorted(
            self.players.values(),
            key=lambda p: (p.state == PlayerState.ALIVE, p.kills, p.damage_dealt),
            reverse=True,
        )

        results = {
            "winner": winner.to_dict() if winner else None,
            "standings": [
                {
                    "rank": i + 1,
                    "player_id": p.player_id,
                    "username": p.username,
                    "kills": p.kills,
                    "damage_dealt": round(p.damage_dealt, 1),
                    "state": p.state.value,
                }
                for i, p in enumerate(standings)
            ],
            "kill_feed": self.kill_feed,
            "match_duration": time.time() - self.server_start_time,
            "match_id": self.match_id,
        }

        await self.broadcast_event("game_over", results)
        logger.info(f"Game over! Winner: {winner.username if winner else 'None'}")

        # Schedule restart
        asyncio.create_task(self._restart_countdown())

    async def _restart_countdown(self):
        await asyncio.sleep(15)
        await self.restart_match()

    async def restart_match(self):
        logger.info("Restarting match...")
        self.match_id = str(uuid.uuid4())[:8]
        self.game_phase = GamePhase.WAITING
        self.countdown_timer = None
        self.zone = Zone(
            center=Vector3(0, 0, 0),
            current_radius=2000,
            target_radius=2000,
            shrink_rate=0,
            damage_per_second=1,
            phase=0,
        )
        self.zone_phase_start_time = None
        self.zone_shrinking = False
        self.kill_feed.clear()
        self.projectiles.clear()
        self.events.clear()
        self.server_start_time = time.time()

        # Regenerate loot
        self.game_map.loot_items.clear()
        self.game_map._spawn_loot()

        # Reset connected players
        for player in self.players.values():
            if player.connected:
                player.state = PlayerState.ALIVE
                player.health = 100
                player.armor = 0
                player.kills = 0
                player.damage_dealt = 0
                player.weapons = [None, None]
                player.inventory.clear()
                player.position = Vector3(
                    random.uniform(-500, 500),
                    500,
                    random.uniform(-500, 500),
                )

        # Remove disconnected players
        disconnected = [pid for pid, p in self.players.items() if not p.connected]
        for pid in disconnected:
            del self.players[pid]

        await self.broadcast_event("match_restart", {
            "match_id": self.match_id,
            "map_data": self.game_map.to_dict(),
        })

    async def broadcast_loop(self):
        """Broadcast full game state to all clients at regular intervals.

        All player positions are sent to all clients.
        Clients are responsible for filtering what to render based on:
        - Distance (render distance / LOD)
        - Line of sight checks
        - Frustum culling
        """
        while self.running:
            try:
                await self.broadcast_game_state()
            except Exception as e:
                logger.error(f"Error in broadcast loop: {e}")

            await asyncio.sleep(1.0 / self.broadcast_rate)

    async def broadcast_game_state(self):
        """Send complete game state to all connected clients.

        We send ALL player positions to ALL clients. This approach:
        1. Simplifies server logic - no per-player view calculation
        2. Enables client-side prediction and interpolation
        3. Allows clients to handle their own LOD and culling
        4. Reduces server CPU load for large player counts
        5. Supports competitive integrity (server is authoritative for game logic)

        Clients filter rendering based on:
        - Distance-based LOD (far players = less detail)
        - Client-side line of sight for audio/visual effects
        - Frustum culling (only render visible players)
        - Minimap can show nearby players
        """
        if not self.connections:
            return

        now = time.time()

        # Build complete player state array - ALL players
        all_players = []
        for player in self.players.values():
            if player.connected or player.state == PlayerState.DEAD:
                all_players.append(player.to_minimal_dict())

        # Build available loot (only non-picked-up items)
        available_loot = []
        for item in self.game_map.loot_items.values():
            if not item.picked_up:
                available_loot.append(item.to_dict())

        # Full game state broadcast
        game_state = {
            "type": "game_state",
            "timestamp": now,
            "server_tick": int((now - self.server_start_time) * self.tick_rate),
            "game_phase": self.game_phase.value,
            "zone": self.zone.to_dict(),
            "alive_count": self.alive_count,
            "total_players": len(self.players),
            # ALL player positions sent to ALL clients
            "players": all_players,
            # Loot state
            "loot_items": available_loot,
            # Active projectiles
            "projectiles": [p.to_dict() for p in self.projectiles.values() if p.active],
            # Recent kill feed
            "kill_feed": self.kill_feed[-5:],
            # Client rendering hints (clients use these for optimization)
            "rendering_hints": {
                "max_render_distance": 1000.0,
                "lod_distances": {
                    "full_detail": 100.0,
                    "medium_detail": 300.0,
                    "low_detail": 600.0,
                    "minimal": 1000.0,
                },
                "audio_range": 200.0,
                "footstep_range": 50.0,
                "gunshot_range": 500.0,
            },
        }

        state_json = json.dumps(game_state)

        # Broadcast to all connected clients simultaneously
        disconnected = []
        send_tasks = []

        for player_id, ws in self.connections.items():
            player = self.players.get(player_id)
            if not player:
                disconnected.append(player_id)
                continue

            # Per-player additions (their own detailed state)
            per_player_state = {
                **json.loads(state_json),
                "your_state": player.to_dict(),
            }

            send_tasks.append(self._safe_send(player_id, ws, json.dumps(per_player_state)))

        if send_tasks:
            await asyncio.gather(*send_tasks)

        for pid in disconnected:
            if pid in self.connections:
                del self.connections[pid]

    async def _safe_send(self, player_id: str, ws, data: str):
        try:
            await ws.send(data)
        except websockets.ConnectionClosed:
            await self.handle_disconnect(player_id)
        except Exception as e:
            logger.error(f"Error sending to {player_id}: {e}")

    async def send_to_player(self, player_id: str, message: dict):
        ws = self.connections.get(player_id)
        if ws:
            try:
                await ws.send(json.dumps(message))
            except websockets.ConnectionClosed:
                await self.handle_disconnect(player_id)
            except Exception as e:
                logger.error(f"Error sending to {player_id}: {e}")

    async def broadcast_event(self, event_type: str, data: dict):
        """Broadcast a game event to all connected clients."""
        event = {
            "type": "event",
            "event_type": event_type,
            "data": data,
            "timestamp": time.time(),
        }

        self.events.append(GameEvent(event_type, data, time.time()))
        if len(self.events) > 100:
            self.events = self.events[-50:]

        event_json = json.dumps(event)
        disconnected = []

        for player_id, ws in self.connections.items():
            try:
                await ws.send(event_json)
            except websockets.ConnectionClosed:
                disconnected.append(player_id)
            except Exception:
                pass

        for pid in disconnected:
            await self.handle_disconnect(pid)


class BattleRoyaleClient:
    """Reference client implementation showing client-side filtering."""

    def __init__(self, uri: str, username: str):
        self.uri = uri
        self.username = username
        self.player_id: Optional[str] = None
        self.ws: Optional[websockets.WebSocketClientProtocol] = None
        self.game_state: dict = {}
        self.my_state: dict = {}
        self.render_distance = 500.0
        self.running = False

    async def connect(self):
        self.ws = await websockets.connect(self.uri)
        await self.ws.send(json.dumps({
            "type": "join",
            "username": self.username,
        }))

        response = json.loads(await self.ws.recv())
        if response["type"] == "welcome":
            self.player_id = response["player_id"]
            logger.info(f"Connected as {self.username} (ID: {self.player_id})")
            self.running = True
            return True
        else:
            logger.error(f"Failed to connect: {response}")
            return False

    async def run(self):
        if not await self.connect():
            return

        receive_task = asyncio.create_task(self.receive_loop())
        input_task = asyncio.create_task(self.input_loop())

        try:
            await asyncio.gather(receive_task, input_task)
        except asyncio.CancelledError:
            pass
        finally:
            if self.ws:
                await self.ws.close()

    async def receive_loop(self):
        try:
            async for raw in self.ws:
                msg = json.loads(raw)
                await self.handle_server_message(msg)
        except websockets.ConnectionClosed:
            logger.info("Disconnected from server")
            self.running = False

    async def handle_server_message(self, msg: dict):
        msg_type = msg.get("type")

        if msg_type == "game_state":
            self.game_state = msg
            self.my_state = msg.get("your_state", {})
            self.process_game_state(msg)

        elif msg_type == "event":
            self.handle_event(msg)

        elif msg_type == "pong":
            client_time = msg.get("client_time", 0)
            ping = (time.time() - client_time) * 1000
            logger.info(f"Ping: {ping:.0f}ms")

        elif msg_type == "hit_marker":
            logger.info(f"Hit! Damage: {msg.get('damage', 0):.0f} "
                        f"{'HEADSHOT!' if msg.get('headshot') else ''}")

        elif msg_type == "position_correction":
            logger.warning("Position corrected by server (anti-cheat)")

    def process_game_state(self, state: dict):
        """Client-side filtering of game state for rendering.

        The server sends ALL player positions. The client decides what to render
        based on distance, line of sight, and performance considerations.
        """
        all_players = state.get("players", [])
        my_pos = self.my_state.get("position", {"x": 0, "y": 0, "z": 0})
        my_position = Vector3.from_dict(my_pos)
        rendering_hints = state.get("rendering_hints", {})
        lod_distances = rendering_hints.get("lod_distances", {})

        # Client-side categorization for rendering
        full_detail_players = []
        medium_detail_players = []
        low_detail_players = []
        minimap_only_players = []
        audio_players = []

        for p in all_players:
            if p["player_id"] == self.player_id:
                continue
            if p["state"] == "dead":
                continue

            p_pos = Vector3.from_dict(p["position"])
            distance = my_position.distance_to(p_pos)

            # Distance-based LOD
            if distance <= lod_distances.get("full_detail", 100):
                full_detail_players.append(p)
            elif distance <= lod_distances.get("medium_detail", 300):
                medium_detail_players.append(p)
            elif distance <= lod_distances.get("low_detail", 600):
                low_detail_players.append(p)
            elif distance <= lod_distances.get("minimal", 1000):
                minimap_only_players.append(p)

            # Audio range
            audio_range = rendering_hints.get("audio_range", 200)
            if distance <= audio_range:
                audio_players.append(p)

        # In a real client, these would be passed to the rendering engine
        total_rendered = (len(full_detail_players) + len(medium_detail_players) +
                          len(low_detail_players))

        zone = state.get("zone", {})
        alive = state.get("alive_count", 0)

        if random.random() < 0.05:  # Occasional log
            logger.info(
                f"[{self.username}] Alive: {alive} | "
                f"Render: {total_rendered} (full:{len(full_detail_players)} "
                f"med:{len(medium_detail_players)} low:{len(low_detail_players)}) | "
                f"Audio: {len(audio_players)} | "
                f"Zone: R={zone.get('current_radius', 0):.0f} Phase={zone.get('phase', 0)}"
            )

    def handle_event(self, msg: dict):
        event_type = msg.get("event_type")
        data = msg.get("data", {})

        if event_type == "kill":
            killer = data.get("killer_name", "Unknown")
            victim = data.get("victim_name", "Unknown")
            weapon = data.get("weapon", "Unknown")
            logger.info(f"[KILL] {killer} eliminated {victim} with {weapon}")

        elif event_type == "zone_shrinking":
            zone = data.get("zone", {})
            logger.info(f"[ZONE] Shrinking to radius {zone.get('target_radius', 0):.0f}")

        elif event_type == "game_over":
            winner = data.get("winner", {})
            if winner:
                logger.info(f"[GAME OVER] Winner: {winner.get('username', 'Unknown')}")
            standings = data.get("standings", [])
            for s in standings[:5]:
                logger.info(f"  #{s['rank']} {s['username']} - "
                            f"{s['kills']} kills, {s['damage_dealt']} damage")

        elif event_type == "player_joined":
            logger.info(f"[JOIN] {data.get('username')} joined "
                        f"({data.get('player_count')} players)")

        elif event_type == "shot_fired":
            pass  # Client would play sound effects based on distance

